  1→// ============================================================
  2→// Background service worker
  3→// Handles scheduled auto-sync, badge updates, and auth flow
  4→// ============================================================
  5→
  6→const ALARM_NAME = 'claude_usage_sync';
  7→const API_BASE = 'https://leaderboard.magizhan.work';
  8→const COOKIE_NAME = 'CF_Authorization';
  9→const COOKIE_DOMAIN = 'leaderboard.magizhan.work';
 10→
 11→// ============================================================
 12→// Auth: JWT from Cloudflare Access cookie
 13→// ============================================================
 14→
 15→/** Read CF_Authorization cookie from leaderboard domain */
 16→async function getAccessCookie() {
 17→  try {
 18→    const cookie = await chrome.cookies.get({
 19→      url: API_BASE,
 20→      name: COOKIE_NAME,
 21→    });
 22→    return cookie ? cookie.value : null;
 23→  } catch (e) {
 24→    return null;
 25→  }
 26→}
 27→
 28→/** Decode JWT payload and check expiry */
 29→function isJWTExpired(jwt) {
 30→  try {
 31→    const parts = jwt.split('.');
 32→    if (parts.length !== 3) return true;
 33→    const payload = JSON.parse(atob(parts[1].replace(/-/g, '+').replace(/_/g, '/')));
 34→    const now = Math.floor(Date.now() / 1000);
 35→    // Treat as expired 5 minutes early to avoid edge cases
 36→    return payload.exp ? payload.exp < now + 300 : false;
 37→  } catch (e) {
 38→    return true;
 39→  }
 40→}
 41→
 42→/** Get email from JWT payload */
 43→function getJWTEmail(jwt) {
 44→  try {
 45→    const parts = jwt.split('.');
 46→    if (parts.length !== 3) return null;
 47→    const payload = JSON.parse(atob(parts[1].replace(/-/g, '+').replace(/_/g, '/')));
 48→    return payload.email || null;
 49→  } catch (e) {
 50→    return null;
 51→  }
 52→}
 53→
 54→/** Get a valid JWT — from cookie, or null if not available */
 55→async function getValidJWT() {
 56→  const jwt = await getAccessCookie();
 57→  if (jwt && !isJWTExpired(jwt)) return jwt;
 58→  return null;
 59→}
 60→
 61→/**
 62→ * Open leaderboard in a tab to trigger CF Access login.
 63→ * Polls for the CF_Authorization cookie until found or timeout.
 64→ */
 65→async function triggerAuth() {
 66→  // Prevent multiple auth tabs
 67→  const state = await chrome.storage.local.get(['auth_in_progress']);
 68→  if (state.auth_in_progress) return { success: false, error: 'Auth already in progress' };
 69→
 70→  await chrome.storage.local.set({ auth_in_progress: true });
 71→
 72→  let tab;
 73→  try {
 74→    tab = await chrome.tabs.create({ url: API_BASE, active: true });
 75→  } catch (e) {
 76→    await chrome.storage.local.remove(['auth_in_progress']);
 77→    return { success: false, error: 'Failed to open auth tab' };
 78→  }
 79→
 80→  const tabId = tab.id;
 81→
 82→  // Listen for tab close
 83→  const tabClosedPromise = new Promise((resolve) => {
 84→    const listener = (closedId) => {
 85→      if (closedId === tabId) {
 86→        chrome.tabs.onRemoved.removeListener(listener);
 87→        resolve('closed');
 88→      }
 89→    };
 90→    chrome.tabs.onRemoved.addListener(listener);
 91→  });
 92→
 93→  // Poll for cookie (every 2s, up to 2 minutes)
 94→  const pollPromise = new Promise((resolve) => {
 95→    let attempts = 0;
 96→    const maxAttempts = 60;
 97→    const interval = setInterval(async () => {
 98→      attempts++;
 99→      const jwt = await getAccessCookie();
100→      if (jwt && !isJWTExpired(jwt)) {
101→        clearInterval(interval);
102→        resolve('authenticated');
103→      } else if (attempts >= maxAttempts) {
104→        clearInterval(interval);
105→        resolve('timeout');
106→      }
107→    }, 2000);
108→  });
109→
110→  const result = await Promise.race([pollPromise, tabClosedPromise]);
111→
112→  await chrome.storage.local.remove(['auth_in_progress']);
113→
114→  if (result === 'authenticated') {
115→    // Close the auth tab
116→    try { await chrome.tabs.remove(tabId); } catch (e) { /* already closed */ }
117→    const jwt = await getAccessCookie();
118→    const email = jwt ? getJWTEmail(jwt) : null;
119→    chrome.action.setBadgeText({ text: '✓' });
120→    chrome.action.setBadgeBackgroundColor({ color: '#22c55e' });
121→    setTimeout(() => chrome.action.setBadgeText({ text: '' }), 5000);
122→    return { success: true, email };
123→  } else if (result === 'closed') {
124→    return { success: false, error: 'Auth tab was closed before login completed' };
125→  } else {
126→    try { await chrome.tabs.remove(tabId); } catch (e) { /* already closed */ }
127→    return { success: false, error: 'Auth timed out. Please try again.' };
128→  }
129→}
130→
131→// ============================================================
132→// Message handling from content.js and popup.js
133→// ============================================================
134→
135→chrome.runtime.onMessage.addListener((msg, sender, sendResponse) => {
136→  if (msg.type === 'get_jwt') {
137→    getValidJWT().then(jwt => sendResponse({ jwt }));
138→    return true; // async response
139→  }
140→
141→  if (msg.type === 'check_auth_status') {
142→    getValidJWT().then(jwt => {
143→      if (jwt) {
144→        sendResponse({ authenticated: true, email: getJWTEmail(jwt) });
145→      } else {
146→        sendResponse({ authenticated: false });
147→      }
148→    });
149→    return true;
150→  }
151→
152→  if (msg.type === 'trigger_auth') {
153→    triggerAuth().then(result => sendResponse(result));
154→    return true;
155→  }
156→
157→  // Proxy API calls through background to avoid CORS (CF Access blocks OPTIONS preflight)
158→  if (msg.type === 'api_fetch') {
159→    (async () => {
160→      try {
161→        const jwt = await getValidJWT();
162→        const headers = { 'Content-Type': 'application/json' };
163→        if (jwt) headers['CF-Access-JWT-Assertion'] = jwt;
164→
165→        const res = await fetch(msg.url, {
166→          method: msg.method || 'POST',
167→          headers,
168→          body: msg.body ? JSON.stringify(msg.body) : undefined,
169→        });
170→
171→        if (res.status === 403) {
172→          sendResponse({ error: 'auth_expired', status: 403 });
173→          return;
174→        }
175→
176→        const data = await res.json();
177→        sendResponse({ ok: true, data, status: res.status });
178→      } catch (e) {
179→        sendResponse({ error: e.message, status: 0 });
180→      }
181→    })();
182→    return true;
183→  }
184→
185→  if (msg.type === 'sync_success') {
186→    chrome.action.setBadgeText({ text: '✓' });
187→    chrome.action.setBadgeBackgroundColor({ color: '#22c55e' });
188→    setTimeout(() => chrome.action.setBadgeText({ text: '' }), 5000);
189→  }
190→});
191→
192→// ============================================================
193→// Scheduled auto-sync via alarm
194→// ============================================================
195→
196→chrome.alarms.onAlarm.addListener(async (alarm) => {
197→  if (alarm.name !== ALARM_NAME) return;
198→
199→  const stored = await chrome.storage.local.get(['schedule_enabled']);
200→  if (!stored.schedule_enabled) return;
201→
